from fastapi import FastAPI, HTTPException, Depends
from pydantic import BaseModel, Field
from sqlalchemy.orm import Session
from typing import List
from datetime import datetime
def get_db():
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()
class EventCreate(BaseModel):
    title: str = Field(..., min_length=1)
    description: str = Field(..., min_length=1)
    start_time: datetime
    end_time: datetime
class EventUpdate(BaseModel):
    title: str = Field(None, min_length=1)
    description: str = Field(None, min_length=1)
    start_time: datetime = None
    end_time: datetime = None
def create_event(db: Session, event: EventCreate):
    db_event = models.Event(**event.dict())
    db.add(db_event)
    db.commit()
    db.refresh(db_event)
    return db_event
def get_events(db: Session):
    return db.query(models.Event).all()
def update_event(db: Session, event_id: int, event_update: EventUpdate):
    db_event = db.query(models.Event).filter(models.Event.id == event_id).first()
    if not db_event:
        raise HTTPException(status_code=404, detail="Event not found")
    for field, value in event_update.dict(exclude_unset=True).items():
        setattr(db_event, field, value)
    db.commit()
    db.refresh(db_event)
    return db_event
def delete_event(db: Session, event_id: int):
    db_event = db.query(models.Event).filter(models.Event.id == event_id).first()
    if not db_event:
        raise HTTPException(status_code=404, detail="Event not found")
    db.delete(db_event)
    db.commit()
    return db_event
app = FastAPI()
@app.post('/events/', response_model=models.Event)
def create_event_endpoint(event: EventCreate, db: Session = Depends(get_db)):
    return create_event(db, event)
@app.get('/events/', response_model=List[models.Event])
def get_events_endpoint(db: Session = Depends(get_db)):
    return get_events(db)
@app.put('/events/{event_id}', response_model=models.Event)
def update_event_endpoint(event_id: int, event_update: EventUpdate, db: Session = Depends(get_db)):
    return update_event(db, event_id, event_update)
@app.delete('/events/{event_id}')
def delete_event_endpoint(event_id: int, db: Session = Depends(get_db)):
    return delete_event(db, event_id)
